VALUES
  ('elementary-f29af906-moex-00588', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '柔柔生長在一個小康的家庭，父母親從小就栽培她學習各項才藝，塑造了柔柔高雅的氣質和談吐。上述 現象最適合用下列那一種概念加以說明？', '["經濟資本", "社會資本", "象徵資本", "文化資本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00589', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '據環保團體估計，每年約有一千多萬噸的塑膠垃圾流入海中，超過 700 種海洋物種受到海洋塑膠污染的 影響，海洋垃圾也造成對船舶航行的阻礙、生態系惡化等不良影響，前述現象最適合用下列何種概念 說明？', '["外部成本內部化", "共有財的悲歌", "搭便車心態", "鄰避效應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00590', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '某甲認為年輕人自己不夠努力因此才買不起房子，某乙反駁認為，許多財團手握大筆資金投入房地產市 場，成為炒房元兇，年輕人靠著微薄的薪水，不論如何努力也永遠追不上高漲的房價。某乙的說法最接 近下列何項觀點？', '["功能論", "衝突論", "成就地位論", "人力資本論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00591', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '美國大選常見各族群文化與價值之間的激辯，但似乎都不影響美國民眾對國家的支持。請問美國人民對 國家的齊心支持，最可能基於下列何項理由？', '["公民身分的保障形成對國家的認同", "國家透過嚴密監控形成公民意識", "透過種族通婚大幅減少社會分歧", "所得平均形成強大的社會凝聚力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00592', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '隨著永續發展思潮的風起雲湧，消費者願意以合理價格，購買以友善耕作方式所生產的蔬果，此種購買 行為符合下列何種概念？', '["綠色廠房", "企業社會責任", "比較利益", "綠色消費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00593', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '阮氏是從東南亞來臺灣從事家庭看護的移工，工作已經一年多，非常細心負責，深受被照顧者李伯伯家 人的喜愛，彼此感情非常好。某日她推著坐在輪椅上的李伯伯要去投票，遭到一輛闖紅燈的機車撞上， 讓她腿部扭傷，醫生評估必須休養兩週。關於阮氏在臺灣享有的權利，下列何者正確？', '["阮氏在臺灣居住已超過四個月，故具有市長投票權", "因阮氏是外國人，故無法獲得肇事者的醫療賠償費", "阮氏在休養期間享有國民年金保險給付的權利", "在臺灣工作期間，雇主可以為阮氏投保勞工保險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00594', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '一名15歲的國中生，下載行政院人事行政總處天然災害停止辦公及上課情形查詢網頁的原始檔案，將其 改成今日起停班、停課一年等內容。這名國中生被依偽造公文書罪函送法辦。下列敘述何者正確？', '["其行為已影響社會至鉅具該當性，所以由檢察官調查起訴", "國中生缺乏對刑法的完整了解，所以其行為不具有違法性", "他只是國中生的年齡，所以他的行為不具備完全的有責性", "該國中生出於好玩，並非故意犯罪，因此他不須負有責性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00595', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '近年來，臺灣多起隨機殺人案件引發社會關注，而部分加害者因罹患思覺失調症而獲判無罪，判決或辯 護理由常引發媒體與大眾的議論。但法治國家就是要在正當法律程序下仔細分析罪犯的動機和成因，律 師的角色是在維護被告基本訴訟權利不被侵犯，而法官則是依法公正審判。若從人權的角度出發，上述 內容是在強調何種權利保障的重要性？', '["行動自由", "公民參政", "社會安全", "公正審判"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00596', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '我國「彈劾權」的設計，與三權分立的國家略有不同。關於我國彈劾權的行使，下列何者正確？', '["立法院可以對行政院院長提出彈劾案", "立法院可調查且彈劾違法的公務人員", "監察院可對違法失職的總統或副總統進行彈劾", "監察院可彈劾縣、市首長並移送司法懲戒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00597', 'elementary-f29af906', 'elementary-f29af906-moex-111-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '我國自1991年至2005年共經歷七次憲法增修，下列何者為修憲的成果？', '["憲法修正案及領土變更案須經人民連署提案", "命令或法律有違憲之虞者由大法官進行解釋", "正副總統彈劾案由立法院提案，憲法法庭審理", "各縣市的縣市長及縣市議員，皆改由人民直選"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:54+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
